#!/bin/bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-05-28

# Integration test for scripts/cc-backfill-changelog-ref.sh (#2041) â€” adds the
# stable `Changelog-Ref: <sha256>` marker to open cc-adoption issues that predate
# the hash-based dedup. Mocks `gh` via PATH-shadow.
#
# Cases:
#   1. issue with `> ref` + no marker â†’ backfilled (1 edit, hash logged)
#   2. issue already carrying Changelog-Ref â†’ skipped (0 edits)
#   3. issue with no `> ref` line â†’ left as-is (0 edits, no-ref)
#   4. DRY_RUN=1 â†’ 0 edits, prints intent
#   5. hash matches the filer's sha256_hex (cross-script key parity)

# Backticks in the fixture strings below are LITERAL markdown (issue-body markers),
# not command substitution â€” single quotes are correct.
# shellcheck disable=SC2016
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"

RED='\033[0;31m'
GREEN='\033[0;32m'
NC='\033[0m'

PASS=0
FAIL=0
log_pass() { echo -e "  ${GREEN}âœ“${NC} $1"; PASS=$((PASS + 1)); }
log_fail() { echo -e "  ${RED}âœ—${NC} $1 â€” $2"; FAIL=$((FAIL + 1)); }

count_calls() {
  local pattern="$1"
  if [ ! -s "$MOCK_LOG" ]; then echo 0; return; fi
  local n
  n=$(grep -cE "${pattern}" "$MOCK_LOG" 2>/dev/null) || n=0  # silent: known-noise
  echo "$n"
}

# Reference sha256 + normalize (must equal the script's sha256_hex âˆ˜ normalize_ref).
sha() { if command -v sha256sum >/dev/null 2>&1; then sha256sum | cut -d' ' -f1; else shasum -a 256 | cut -d' ' -f1; fi; }
norm() { sed -E 's/^[[:space:]]*[-*+][[:space:]]+//; s/[[:space:]]+/ /g; s/^[[:space:]]+//; s/[[:space:]]+$//'; }

echo "CC Backfill Changelog-Ref â€” migration tests"
echo "========================================================="

MOCK_DIR=$(mktemp -d)
MOCK_LOG="$MOCK_DIR/gh.log"
export MOCK_LOG
cat > "$MOCK_DIR/gh" <<'MOCK'
#!/usr/bin/env bash
# gh mock: records calls; emits canned data via env.
#   MOCK_NUMS  newline-separated issue numbers for `issue list`
#   MOCK_BODY  body returned by `issue view --json body --jq .body`
set -euo pipefail
printf '%s\n' "$*" >> "$MOCK_LOG"
case "$1 $2" in
  "issue list") printf '%s\n' "${MOCK_NUMS:-100}" ;;
  "issue view") printf '%s' "${MOCK_BODY:-}" ;;
  "issue edit") : ;;
  *) echo "MOCK_GH unhandled: $*" >&2; exit 1 ;;
esac
exit 0
MOCK
chmod +x "$MOCK_DIR/gh"
export PATH="$MOCK_DIR:$PATH"
cleanup() { rm -rf "$MOCK_DIR"; }
trap cleanup EXIT

SCRIPT="$PROJECT_ROOT/scripts/cc-backfill-changelog-ref.sh"
EDIT_RE='^issue edit [0-9]+ '
REFLINE='`claude plugin marketplace remove` now accepts --scope'
EXPECTED_HASH=$(printf '%s' "$REFLINE" | norm | sha)

# Body that the filer would have written: a `> <ref>` blockquote, no marker yet.
BODY_NO_MARKER=$(printf '%s\n\n%s\n\n%s\n\n> %s\n' \
  '**Auto-filed by cc-release-watch**' '**Key:** `marketplace_remove_scope_flag+2.1.152`' \
  '## Changelog reference' "$REFLINE")
BODY_WITH_MARKER=$(printf '%s\n\n**Changelog-Ref:** `%s`' "$BODY_NO_MARKER" "$EXPECTED_HASH")
BODY_NO_REF=$(printf '%s\n\n%s\n' '**Key:** `foo+2.1.152`' 'no blockquote here')

# ============================================================================
# Case 1: unmarked issue with a `> ref` â†’ backfilled once
# ============================================================================
: > "$MOCK_LOG"; EXIT=0
MOCK_NUMS=100 MOCK_BODY="$BODY_NO_MARKER" SLEEP_BETWEEN=0 GH_REPO="acme/orchestkit" \
  bash "$SCRIPT" >/tmp/bf-1.out 2>&1 || EXIT=$?
if [ "$EXIT" = "0" ] && [ "$(count_calls "$EDIT_RE")" = "1" ] && grep -q "added Changelog-Ref" /tmp/bf-1.out; then
  log_pass "backfills an unmarked issue (1 edit)"
else
  log_fail "backfill" "expected exit 0 + 1 edit + 'added' (see /tmp/bf-1.out)"
fi
if grep -qF "$EXPECTED_HASH" /tmp/bf-1.out; then
  log_pass "computed hash matches the filer's sha256_hex (key parity)"
else
  log_fail "hash parity" "expected $EXPECTED_HASH in output (see /tmp/bf-1.out)"
fi

# ============================================================================
# Case 2: already-marked issue â†’ skipped
# ============================================================================
: > "$MOCK_LOG"; EXIT=0
MOCK_NUMS=100 MOCK_BODY="$BODY_WITH_MARKER" GH_REPO="acme/orchestkit" \
  bash "$SCRIPT" >/tmp/bf-2.out 2>&1 || EXIT=$?
if [ "$EXIT" = "0" ] && [ "$(count_calls "$EDIT_RE")" = "0" ] && grep -q "already-marked=1" /tmp/bf-2.out; then
  log_pass "idempotent: already-marked issue skipped (0 edits)"
else
  log_fail "idempotent" "expected 0 edits + already-marked=1 (see /tmp/bf-2.out)"
fi

# ============================================================================
# Case 3: issue with no `> ref` line â†’ left as-is
# ============================================================================
: > "$MOCK_LOG"; EXIT=0
MOCK_NUMS=100 MOCK_BODY="$BODY_NO_REF" GH_REPO="acme/orchestkit" \
  bash "$SCRIPT" >/tmp/bf-3.out 2>&1 || EXIT=$?
if [ "$EXIT" = "0" ] && [ "$(count_calls "$EDIT_RE")" = "0" ] && grep -q "no-ref=1" /tmp/bf-3.out; then
  log_pass "no '> ref' line â†’ left as-is (0 edits)"
else
  log_fail "no-ref" "expected 0 edits + no-ref=1 (see /tmp/bf-3.out)"
fi

# ============================================================================
# Case 4: DRY_RUN=1 â†’ 0 edits, prints intent
# ============================================================================
: > "$MOCK_LOG"; EXIT=0
DRY_RUN=1 MOCK_NUMS=100 MOCK_BODY="$BODY_NO_MARKER" GH_REPO="acme/orchestkit" \
  bash "$SCRIPT" >/tmp/bf-4.out 2>&1 || EXIT=$?
if [ "$EXIT" = "0" ] && [ "$(count_calls "$EDIT_RE")" = "0" ] && grep -q "DRY_RUN: would add" /tmp/bf-4.out; then
  log_pass "DRY_RUN: prints intent, 0 edits"
else
  log_fail "DRY_RUN" "expected 0 edits + 'would add' (see /tmp/bf-4.out)"
fi

# ============================================================================
# Case 6: cross-format parity (#2041 review) â€” a `- `-bullet-prefixed body hashes
# to the SAME key as the bare form (normalize_ref strips the bullet). This is what
# lets the snapshot's "- <line>" and the LLM's de-bulleted ref dedup together.
# ============================================================================
: > "$MOCK_LOG"; EXIT=0
BODY_BULLET=$(printf '%s\n\n%s\n\n> - %s\n' '**Auto-filed**' '## Changelog reference' "$REFLINE")
MOCK_NUMS=100 MOCK_BODY="$BODY_BULLET" SLEEP_BETWEEN=0 GH_REPO="acme/orchestkit" \
  bash "$SCRIPT" >/tmp/bf-6.out 2>&1 || EXIT=$?
if [ "$EXIT" = "0" ] && grep -qF "$EXPECTED_HASH" /tmp/bf-6.out; then
  log_pass "cross-format parity: '- '-prefixed ref hashes identical to the bare ref"
else
  log_fail "cross-format parity" "expected hash $EXPECTED_HASH for bulleted body (see /tmp/bf-6.out)"
fi

echo "========================================================="
echo -e "Passed: ${GREEN}${PASS}${NC}  Failed: ${RED}${FAIL}${NC}"
[ "$FAIL" -eq 0 ]
